# JavaScript Function Declarations and Expressions

```javascript
// Function declaration
function multiply(a, b) {
  return a * b;
}

// Function expression
const divide = function(a, b) {
  return a / b;
};

// Using functions
let resultMultiply = multiply(4, 5);
let resultDivide = divide(20, 4);
console.log(`Multiplication Result: ${resultMultiply}`); // Output: 20
console.log(`Division Result: ${resultDivide}`); // Output: 5
```

### Key Points:

| Function Type       | Syntax                                  | Example Call           |
|---------------------|-----------------------------------------|------------------------|
| Declaration         | `function name(params) { ... }`         | `multiply(4, 5)`       |
| Expression          | `const name = function(params) { ... };`| `divide(20, 4)`        |

# JavaScript Scope, Closures, and 'this' Keyword

```javascript
// Global scope
let globalVar = 'I am global';

function outerFunction(outerVar) {
  // Local scope
  let innerVar = 'I am inner';

  function innerFunction() {
    console.log(globalVar); // Access global variable
    console.log(outerVar); // Access outerFunction's parameter
    console.log(innerVar); // Access own local scope
  }

  return innerFunction;
}

const createClosure = outerFunction('I am outer');
createClosure();

// Object with method using this keyword
const person = {
  name: 'Alice',
  greet: function() {
    console.log(`Hello, my name is ${this.name}`);
  }
};
person.greet(); // Output: Hello, my name is Alice
```

